CREATE TABLE IF NOT EXISTS "score_sections" (
"year" INTEGER,
  "score" INTEGER,
  "物理_本段人数" INTEGER,
  "物理_累计人数" INTEGER,
  "化学_本段人数" INTEGER,
  "化学_累计人数" INTEGER,
  "生物_本段人数" INTEGER,
  "生物_累计人数" INTEGER,
  "政治_本段人数" INTEGER,
  "政治_累计人数" INTEGER,
  "历史_本段人数" INTEGER,
  "历史_累计人数" INTEGER,
  "地理_本段人数" INTEGER,
  "地理_累计人数" INTEGER,
  "全体_本段" INTEGER,
  "全体_累计" INTEGER
);
CREATE INDEX idx_year_score ON score_sections (year, score);
